import{_ as d,c as r,o,aj as p}from"./chunks/framework.CynFBi0q.js";const b=JSON.parse('{"title":"第6章 交互原型设计 — Axure 实战","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-product/chapter_6.md","filePath":"handbook/ai-product/chapter_6.md","lastUpdated":1782008855000}'),a={name:"handbook/ai-product/chapter_6.md"};function e(l,t,h,i,n,u){return o(),r("div",null,[...t[0]||(t[0]=[p('<h1 id="第6章-交互原型设计-—-axure-实战" tabindex="-1">第6章 交互原型设计 — Axure 实战 <a class="header-anchor" href="#第6章-交互原型设计-—-axure-实战" aria-label="Permalink to “第6章 交互原型设计 — Axure 实战”">​</a></h1><p>原型是产品经理的语言。评审会上，你说半天不如给一个可交互的原型。开发看了原型就知道要做什么，设计看了原型就知道风格方向。</p><p>我是怕浪猫，这一章不讲交互设计理论（理论你在其他地方看过无数遍了），只讲怎么用Axure画出一个&quot;开发看了就知道怎么做&quot;的原型。</p><h2 id="_6-1-axure-工具基础" tabindex="-1">6.1 Axure 工具基础 <a class="header-anchor" href="#_6-1-axure-工具基础" aria-label="Permalink to “6.1 Axure 工具基础”">​</a></h2><h3 id="_6-1-1-axure-界面认知与基本操作" tabindex="-1">6.1.1 Axure 界面认知与基本操作 <a class="header-anchor" href="#_6-1-1-axure-界面认知与基本操作" aria-label="Permalink to “6.1.1 Axure 界面认知与基本操作”">​</a></h3><p>Axure的界面分五个区域：</p><p><strong>页面面板（左侧）</strong>：管理页面结构。像文件夹一样，可以建子页面、拖拽排序、批量删除。</p><p><strong>元件面板（左侧下方）</strong>：Axure内置的元件库。包括基础元件（矩形、文本、图片）、表单元件（输入框、按钮、下拉框）、菜单表格等。熟悉元件库是画原型的基础。</p><p><strong>画布面板（中间）</strong>：原型的主编辑区。拖拽元件到画布上，排列组合。</p><p><strong>样式面板（右侧）</strong>：调整元件的样式。位置、尺寸、填充色、边框、阴影、圆角。常用快捷键：Ctrl+D复制元件，Ctrl+G编组，Ctrl+Shift+G解组。</p><p><strong>交互面板（右侧下方）</strong>：添加交互行为。点击、鼠标悬停、键盘事件等。交互是Axure区别于Sketch/Figma的核心能力。</p><p><strong>五个核心快捷键</strong></p><table tabindex="0"><thead><tr><th>快捷键</th><th>作用</th></tr></thead><tbody><tr><td>Ctrl+D</td><td>复制元件</td></tr><tr><td>Ctrl+G</td><td>将选中的元件编组</td></tr><tr><td>Ctrl+Shift+G</td><td>解组</td></tr><tr><td>F5</td><td>预览原型</td></tr><tr><td>Ctrl+S</td><td>保存</td></tr></tbody></table><h3 id="_6-1-2-元件库与页面管理" tabindex="-1">6.1.2 元件库与页面管理 <a class="header-anchor" href="#_6-1-2-元件库与页面管理" aria-label="Permalink to “6.1.2 元件库与页面管理”">​</a></h3><p><strong>内置元件的使用</strong></p><p>Axure的内置元件非常丰富，熟练使用这些元件能大幅提升效率：</p><p>基础元件：矩形（最常用）、文本标签、图片、热区 表单元件：文本框、文本域、下拉框、单选框、复选框、按钮 高级元件：动态面板、中继器、母菜单、树</p><p><strong>动态面板（Dynamic Panel）</strong></p><p>动态面板是Axure中最强大的元件。简单理解：动态面板就是&quot;带状态的元件&quot;。</p><p>举例：一个Tab切换器，包含&quot;推荐&quot;和&quot;热门&quot;两个Tab。每个Tab对应不同的内容。通过动态面板，可以实现点击Tab时切换显示不同的内容。</p><p>操作方法：选中Tab按钮，在交互面板中添加&quot;点击时设置面板状态&quot;的动作。</p><p><strong>中继器（Repeater）</strong></p><p>中继器是&quot;可复制的元件组&quot;。适合做列表页、卡片流等重复性内容。</p><p>操作方法：先设计一个&quot;列表项&quot;模板，然后给中继器设置数据源（手动输入或导入Excel），中继器会自动复制模板并填充数据。</p><h3 id="_6-1-3-交互事件与动作设置" tabindex="-1">6.1.3 交互事件与动作设置 <a class="header-anchor" href="#_6-1-3-交互事件与动作设置" aria-label="Permalink to “6.1.3 交互事件与动作设置”">​</a></h3><p>Axure的交互通过&quot;事件+动作&quot;来实现。</p><p><strong>常用事件类型</strong></p><table tabindex="0"><thead><tr><th>事件</th><th>触发条件</th></tr></thead><tbody><tr><td>OnClick</td><td>单击</td></tr><tr><td>OnMouseEnter</td><td>鼠标悬停</td></tr><tr><td>OnMouseOut</td><td>鼠标离开</td></tr><tr><td>OnFocus</td><td>获得焦点（输入框）</td></tr><tr><td>OnLostFocus</td><td>失去焦点</td></tr><tr><td>OnKeyUp</td><td>键盘按键释放</td></tr><tr><td>OnLoad</td><td>页面加载时</td></tr></tbody></table><p><strong>常用动作类型</strong></p><table tabindex="0"><thead><tr><th>动作</th><th>说明</th></tr></thead><tbody><tr><td>Set Text</td><td>设置文本内容</td></tr><tr><td>Set Image</td><td>切换图片</td></tr><tr><td>Show</td><td>显示元件</td></tr><tr><td>Hide</td><td>隐藏元件</td></tr><tr><td>Toggle</td><td>切换显示/隐藏</td></tr><tr><td>Move</td><td>移动元件位置</td></tr><tr><td>Set Panel State</td><td>切换动态面板状态</td></tr><tr><td>Open Link</td><td>打开链接/页面</td></tr></tbody></table><p><strong>一个完整的交互示例：Tab切换器</strong></p><p>Step 1：画Tab栏。两个按钮&quot;推荐&quot;和&quot;热门&quot;。</p><p>Step 2：画两个动态面板，每个Tab对应一个面板状态。</p><ul><li>&quot;推荐&quot;面板状态：显示推荐内容</li><li>&quot;热门&quot;面板状态：显示热门内容</li></ul><p>Step 3：给&quot;推荐&quot;按钮添加OnClick事件，动作是&quot;设置面板状态为推荐&quot;。</p><p>Step 4：给&quot;热门&quot;按钮添加OnClick事件，动作是&quot;设置面板状态为热门&quot;。</p><p>Step 5：预览（F5），点击Tab即可切换。</p><p><strong>条件逻辑：if-else判断</strong></p><p>实际产品的交互很少是&quot;点击就完事&quot;那么简单。更多时候，交互是有条件的——满足条件走A路径，不满足走B路径。Axure支持在交互动作上添加条件判断，这就是条件逻辑。</p><p>举个实战例子：登录按钮的交互。</p><ul><li>如果用户名和密码都填写了 → 按钮可点击，跳转到首页</li><li>如果用户名或密码为空 → 按钮禁用，点击无响应</li><li>如果密码错误 → 弹出错误提示</li></ul><p>在Axure中实现：</p><ol><li>选中登录按钮，添加OnClick事件</li><li>添加条件：如果&quot;用户名输入框文字不为空&quot;且&quot;密码输入框文字不为空&quot; → 动作：Open Link跳转首页</li><li>添加Else If：如果&quot;密码输入框文字&quot;等于&quot;123456&quot; → 动作：Show错误提示&quot;密码过于简单&quot;</li><li>添加Else → 动作：Show错误提示&quot;请填写完整信息&quot;</li></ol><p>条件编辑器支持的逻辑运算符：等于、不等于、包含、不包含、大于、小于、为空、不为空。多个条件之间可以设置&quot;且&quot;（全部满足）或&quot;或&quot;（满足任一）关系。</p><p><strong>条件逻辑的典型应用场景</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>条件判断</th><th>满足时行为</th><th>不满足时行为</th></tr></thead><tbody><tr><td>表单提交</td><td>所有必填项已填</td><td>提交成功</td><td>高亮未填项</td></tr><tr><td>权限控制</td><td>用户角色=管理员</td><td>显示管理入口</td><td>隐藏管理入口</td></tr><tr><td>库存判断</td><td>库存&gt;0</td><td>可加入购物车</td><td>显示&quot;已售罄&quot;</td></tr><tr><td>金额判断</td><td>订单金额&gt;=99</td><td>免运费</td><td>显示运费</td></tr><tr><td>版本判断</td><td>用户版本=VIP</td><td>解锁高级功能</td><td>弹出升级提示</td></tr></tbody></table><p><strong>变量使用：全局变量与局部变量</strong></p><p>条件逻辑离不开变量。Axure中的变量分两种：全局变量和局部变量。</p><p>全局变量：在整个原型中任何页面、任何元件都可以读取和修改。适合存储跨页面的状态信息。比如用户登录状态、购物车商品数量、当前选择的城市。</p><p>局部变量：只在当前交互动作的作用域内有效。适合临时计算或临时存储。比如获取某个输入框的当前文字、计算两个数值的差值。</p><p><strong>全局变量的设置方法</strong>：顶部菜单 → 项目 → 全局变量 → 添加变量。建议命名规范：用大写+下划线，如USER_ROLE、CART_COUNT、IS_LOGGED_IN。</p><p><strong>局部变量的设置方法</strong>：在添加交互动作时，点击&quot;fx&quot;按钮 → 添加局部变量 → 选择变量来源（元件文字、变量值等）。</p><p><strong>实战案例：购物车数量同步</strong></p><p>需求：商品详情页点击&quot;加入购物车&quot;，底部Tab栏的购物车图标上显示红点数字。</p><p>实现步骤：</p><ol><li>创建全局变量CART_COUNT，初始值设为0</li><li>商品详情页的&quot;加入购物车&quot;按钮，OnClick事件添加动作：设置变量CART_COUNT = CART_COUNT + 1</li><li>底部Tab栏购物车图标旁的文本标签，在页面OnLoad事件中设置文字 = [[CART_COUNT]]</li><li>每次页面加载时，文本标签会自动读取CART_COUNT的值并显示</li></ol><p><strong>变量使用注意事项</strong></p><table tabindex="0"><thead><tr><th>事项</th><th>说明</th></tr></thead><tbody><tr><td>命名规范</td><td>全局变量大写+下划线，局部变量小写+下划线</td></tr><tr><td>初始值</td><td>全局变量必须设置初始值，否则原型预览时会报错</td></tr><tr><td>数量控制</td><td>全局变量不要超过20个，多了难以维护</td></tr><tr><td>数值运算</td><td>Axure变量本质是字符串，做加减运算时用[[变量名*1]]强制转数字</td></tr><tr><td>跨页面传递</td><td>全局变量天然跨页面，局部变量只能在当前交互中使用</td></tr></tbody></table><h2 id="_6-2-交互原型绘制" tabindex="-1">6.2 交互原型绘制 <a class="header-anchor" href="#_6-2-交互原型绘制" aria-label="Permalink to “6.2 交互原型绘制”">​</a></h2><h3 id="_6-2-1-交互设计原理与原则" tabindex="-1">6.2.1 交互设计原理与原则 <a class="header-anchor" href="#_6-2-1-交互设计原理与原则" aria-label="Permalink to “6.2.1 交互设计原理与原则”">​</a></h3><p>交互设计不是&quot;炫技&quot;，而是&quot;降低认知成本&quot;。</p><p><strong>交互设计五原则</strong></p><p>原则一：一致性。相似的操作应该有相似的结果。同样的交互在不同地方表现一致，用户才能建立稳定的认知。</p><p>原则二：反馈及时性。用户的每一个操作都应该有即时的反馈。点击按钮后显示loading状态，操作完成后显示成功提示。</p><p>原则三：容错设计。允许用户犯错，并且提供撤销/恢复的途径。删除操作有确认提示，错误输入有明确提示。</p><p>原则四：效率优先。不要让用户做重复操作。如果能记住用户的偏好，就不要让用户每次都重新设置。</p><p>原则五：渐进式披露。不要一次性展示所有功能。先展示核心功能，高级功能在需要时再出现。</p><h3 id="_6-2-2-页面布局与信息层级" tabindex="-1">6.2.2 页面布局与信息层级 <a class="header-anchor" href="#_6-2-2-页面布局与信息层级" aria-label="Permalink to “6.2.2 页面布局与信息层级”">​</a></h3><p>页面布局的核心是&quot;信息层级&quot;——让用户知道&quot;先看什么、后看什么&quot;。</p><p><strong>三种经典布局模式</strong></p><table tabindex="0"><thead><tr><th>布局模式</th><th>特征</th><th>适用场景</th><th>示例</th></tr></thead><tbody><tr><td>F型布局</td><td>顶部和左侧信息优先级高</td><td>资讯类产品</td><td>今日头条</td></tr><tr><td>Z型布局</td><td>左上→右上→左下→右下</td><td>营销落地页</td><td>淘宝banner</td></tr><tr><td>卡片式布局</td><td>内容块独立，灵活组合</td><td>社交/内容流</td><td>微博、抖音</td></tr></tbody></table><p><strong>信息层级处理</strong></p><p>层级一：大标题+副标题。告诉用户&quot;这是什么东西&quot;。</p><p>层级二：核心内容。用户打开页面第一眼要看到的信息。</p><p>层级三：辅助信息。用户在需要时才会查找的信息。</p><p>层级四：操作入口。用户要执行的动作。</p><p>原型中的视觉层级处理：字号大小、颜色深浅、留白间距都能区分层级。在Axure中，通过调整字体大小（标题24px、正文16px、辅助12px）和间距来建立清晰的层级。</p><h3 id="_6-2-3-交互状态设计-默认-悬停-激活-禁用" tabindex="-1">6.2.3 交互状态设计（默认/悬停/激活/禁用） <a class="header-anchor" href="#_6-2-3-交互状态设计-默认-悬停-激活-禁用" aria-label="Permalink to “6.2.3 交互状态设计（默认/悬停/激活/禁用）”">​</a></h3><p>好的交互设计要让用户感知到&quot;系统的响应&quot;。状态设计是实现这一点的关键。</p><p><strong>按钮的四状态</strong></p><table tabindex="0"><thead><tr><th>状态</th><th>视觉表现</th><th>交互行为</th></tr></thead><tbody><tr><td>默认</td><td>正常颜色</td><td>无特殊行为</td></tr><tr><td>悬停</td><td>颜色加深/轻微上移</td><td>鼠标悬停时触发</td></tr><tr><td>按下</td><td>颜色进一步加深/轻微下沉</td><td>鼠标按下时触发</td></tr><tr><td>禁用</td><td>灰色，无法点击</td><td>灰色状态，无法交互</td></tr></tbody></table><p><strong>输入框的三状态</strong></p><table tabindex="0"><thead><tr><th>状态</th><th>视觉表现</th></tr></thead><tbody><tr><td>默认</td><td>灰色边框</td></tr><tr><td>聚焦</td><td>蓝色边框，光标闪烁</td></tr><tr><td>错误</td><td>红色边框，错误提示文字</td></tr><tr><td>禁用</td><td>灰色背景，无法输入</td></tr></tbody></table><p><strong>列表项的交互</strong></p><table tabindex="0"><thead><tr><th>状态</th><th>视觉表现</th></tr></thead><tbody><tr><td>默认</td><td>正常显示</td></tr><tr><td>悬停</td><td>背景色变化，暗示可点击</td></tr><tr><td>按下</td><td>背景色变化（比悬停更深）</td></tr><tr><td>选中</td><td>左侧出现选中指示器，如蓝色竖条</td></tr></tbody></table><p><strong>表单验证状态设计</strong></p><p>表单是用户输入信息的核心载体，验证状态设计做得好不好直接决定用户能不能顺利填完。怕浪猫见过太多原型只画了&quot;输入框+按钮&quot;就完事，开发一看一脸懵：输了不对怎么办？哪儿不对？怎么提示？</p><p>表单验证分两种时机：实时验证和提交验证。</p><p>实时验证：用户在输入过程中即时反馈。适合格式类校验——手机号位数、邮箱格式、密码强度。用户输完一个字段就能知道对不对，不用等到点提交。</p><p>提交验证：用户点击提交按钮后统一校验。适合业务逻辑类校验——用户名是否已注册、优惠券是否过期。这类校验需要请求后端，无法实时完成。</p><p><strong>表单验证状态一览</strong></p><table tabindex="0"><thead><tr><th>状态</th><th>触发时机</th><th>视觉表现</th><th>交互行为</th></tr></thead><tbody><tr><td>未填写</td><td>页面初始加载</td><td>灰色占位符文字</td><td>无</td></tr><tr><td>正在输入</td><td>获得焦点并输入</td><td>蓝色边框，输入内容实时显示</td><td>可选：实时校验提示</td></tr><tr><td>输入正确</td><td>失去焦点时校验通过</td><td>绿色边框+对勾图标</td><td>无</td></tr><tr><td>输入错误</td><td>失去焦点时校验不通过</td><td>红色边框+错误提示文字</td><td>错误提示在输入框下方，文字要具体</td></tr><tr><td>禁用</td><td>特定条件未满足</td><td>灰色背景，不可编辑</td><td>鼠标悬停可提示禁用原因</td></tr></tbody></table><p><strong>错误提示样式规范</strong></p><p>错误提示不能只说&quot;输入有误&quot;，要告诉用户具体哪里错了、怎么改。这是产品经理的责任，不要丢给开发去猜。</p><table tabindex="0"><thead><tr><th>错误类型</th><th>错误提示文案（反面教材）</th><th>错误提示文案（正确写法）</th></tr></thead><tbody><tr><td>必填为空</td><td>请填写信息</td><td>请输入手机号</td></tr><tr><td>格式错误</td><td>格式不正确</td><td>手机号应为11位数字</td></tr><tr><td>长度不足</td><td>长度太短</td><td>密码至少8位，还需输入N位</td></tr><tr><td>重复提交</td><td>操作失败</td><td>该手机号已注册，可直接登录</td></tr><tr><td>超出限制</td><td>输入超限</td><td>最多输入200字，已超出N字</td></tr></tbody></table><p>在Axure中的实现方式：每个输入框下方预留一个文本标签（默认隐藏），校验不通过时Show该标签并设置错误文字。</p><p><strong>加载状态设计</strong></p><p>用户点击操作后到结果出来之前，这段时间就是加载状态。处理不好加载状态，用户就会以为系统卡死了，疯狂点击按钮，重复提交请求。</p><p>加载状态有三种主流方案：骨架屏、loading动画、进度条。选哪个取决于场景。</p><p><strong>三种加载状态对比</strong></p><table tabindex="0"><thead><tr><th>方案</th><th>适用场景</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>骨架屏</td><td>页面首次加载、内容区域加载</td><td>用户能预判内容结构，感知等待时间短</td><td>需要设计骨架图，开发成本稍高</td></tr><tr><td>Loading动画</td><td>操作反馈（提交、保存、删除）</td><td>实现简单，通用性强</td><td>不知道要等多久，长时间等待焦虑</td></tr><tr><td>进度条</td><td>文件上传、批量处理、安装过程</td><td>用户知道进度，焦虑感最低</td><td>必须能获取真实进度，假进度反而更差</td></tr></tbody></table><p><strong>骨架屏设计要点</strong></p><p>骨架屏的本质是&quot;占位&quot;。用灰色色块代替真实内容，让用户提前感知页面结构。</p><p>设计规范：</p><ul><li>色块颜色用#F2F2F2或#E5E5E5，和背景形成轻微对比</li><li>圆角、间距和真实内容保持一致</li><li>文字行用圆角矩形代替，图片区域用方形色块</li><li>可以加一个从左到右的微光扫过动画（shimmer效果），暗示正在加载</li></ul><p>在Axure中实现：画一个和真实页面结构完全一致的灰色版本，放在动态面板的&quot;加载中&quot;状态。页面OnLoad时先显示骨架屏状态，用Set Interval或Wait动作模拟2秒后切换到真实内容状态。</p><p><strong>Loading动画设计要点</strong></p><p>Loading动画用在哪里：按钮点击后、数据提交时、异步请求等待时。</p><p>设计规范：</p><ul><li>按钮内的Loading：按钮文字变为&quot;提交中...&quot;，左侧加旋转图标，按钮置灰不可再次点击</li><li>页面级Loading：在内容区域居中显示旋转图标+&quot;加载中&quot;文字</li><li>时间预估：如果请求通常&lt;1秒，只显示按钮内Loading即可；如果&gt;1秒，需要页面级Loading</li><li>防重复提交：Loading期间按钮必须禁用，这是基本常识</li></ul><p><strong>进度条设计要点</strong></p><p>进度条适合可量化的进度场景。关键原则：进度必须是真实的。</p><p>设计规范：</p><ul><li>显示百分比数字：&quot;已上传 67%&quot;</li><li>显示具体数据：&quot;已上传 34MB / 50MB&quot;</li><li>预估剩余时间：&quot;预计还需 2分钟&quot;</li><li>失败时可重试：进度条变红，显示&quot;上传失败&quot;+重试按钮</li></ul><p>绝对不要做&quot;假进度条&quot;——那种到99%就停住然后突然跳完成的，用户一看就知道是假的，信任感直接崩塌。</p><h3 id="_6-2-4-从低保真到高保真原型" tabindex="-1">6.2.4 从低保真到高保真原型 <a class="header-anchor" href="#_6-2-4-从低保真到高保真原型" aria-label="Permalink to “6.2.4 从低保真到高保真原型”">​</a></h3><p><strong>低保真vs高保真</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>特征</th><th>适用场景</th><th>工具</th></tr></thead><tbody><tr><td>低保真</td><td>线条和方框，无细节</td><td>快速验证想法</td><td>纸和笔、白板</td></tr><tr><td>中保真</td><td>有色块和基本交互</td><td>评审和讨论</td><td>Axure基础功能</td></tr><tr><td>高保真</td><td>接近真实设计稿</td><td>开发参考、用户测试</td><td>Axure+图片+Figma</td></tr></tbody></table><p><strong>高保真原型制作流程</strong></p><p>第一步：标注设计稿。把UI设计稿导入Axure，放在每个页面的背景层（设为隐藏），然后在背景层上覆盖元件。</p><p>第二步：精确还原设计稿的视觉。字号、颜色、间距、圆角——每一个细节都要对齐设计稿。</p><p>第三步：添加全部交互。包括加载状态、空状态、错误状态、边界处理。</p><p>第四步：添加页面跳转。从首页到详情页，从列表到筛选结果——完整的用户路径都要通。</p><p>第五步：自检和测试。在Axure中模拟用户操作，检查每一个交互是否流畅。</p><blockquote><p>原型不是&quot;画完就完了&quot;，而是&quot;开发看了就知道怎么做&quot;。一个好的原型，能让开发减少80%的疑问。</p></blockquote><p><strong>原型评审checklist</strong></p><p>评审原型不是&quot;看看有没有漏画元件&quot;，而是要从用户视角走一遍完整流程。怕浪猫每次评审前都会过一遍这个清单，能筛出80%的低级问题。</p><p><strong>功能完整性</strong></p><table tabindex="0"><thead><tr><th>检查项</th><th>检查标准</th><th>常见问题</th></tr></thead><tbody><tr><td>主流程是否完整</td><td>从入口到结束的全部页面是否都有</td><td>只画了一半流程，后面页面缺失</td></tr><tr><td>分支流程是否覆盖</td><td>每个选择点的不同结果是否有对应页面</td><td>只画了成功路径，失败路径没画</td></tr><tr><td>操作闭环是否形成</td><td>每一步操作后用户下一步去哪</td><td>操作完成后没有反馈，用户不知道成功了没</td></tr><tr><td>核心功能是否可交互</td><td>关键按钮、表单、筛选是否都能点击</td><td>只做静态展示，没有真实交互</td></tr></tbody></table><p><strong>交互一致性</strong></p><table tabindex="0"><thead><tr><th>检查项</th><th>检查标准</th><th>常见问题</th></tr></thead><tbody><tr><td>相同元件状态是否一致</td><td>所有按钮的悬停、按下状态统一</td><td>不同页面的按钮颜色、圆角不一致</td></tr><tr><td>交互反馈是否统一</td><td>同样的操作在不同地方反馈相同</td><td>有的地方成功弹窗，有的地方成功toast</td></tr><tr><td>返回逻辑是否一致</td><td>每个页面从哪来回哪去</td><td>点返回时有时候回首页，有时候回上一页</td></tr><tr><td>手势/快捷键是否一致</td><td>同类型操作用同样的手势或快捷键</td><td>列表页左滑删除，详情页右滑删除</td></tr></tbody></table><p><strong>边界情况</strong></p><table tabindex="0"><thead><tr><th>检查项</th><th>检查标准</th><th>常见问题</th></tr></thead><tbody><tr><td>超长内容如何处理</td><td>文字超长、列表超长、图片超长</td><td>没做截断、换行或滚动</td></tr><tr><td>数量边界</td><td>数量为0、为1、达到上限</td><td>没有上限提示，数量爆了页面布局错乱</td></tr><tr><td>时间边界</td><td>活动开始/结束、倒计时</td><td>活动结束后页面没变化</td></tr><tr><td>权限边界</td><td>游客、普通用户、VIP</td><td>不同角色看到的内容没有区分</td></tr></tbody></table><p><strong>空状态处理</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>空状态表现</th><th>错误做法</th></tr></thead><tbody><tr><td>列表无数据</td><td>显示空状态插画+引导文字+操作按钮</td><td>直接白屏，用户不知道是没数据还是加载失败</td></tr><tr><td>搜索结果为空</td><td>提示&quot;暂无结果&quot;+推荐搜索词</td><td>显示&quot;0条结果&quot;就完事</td></tr><tr><td>网络异常</td><td>显示错误提示+重试按钮</td><td>页面空白，用户反复刷新</td></tr><tr><td>无权限</td><td>说明原因+引导升级/登录</td><td>直接显示403错误</td></tr></tbody></table><p><strong>错误处理</strong></p><table tabindex="0"><thead><tr><th>检查项</th><th>检查标准</th><th>常见问题</th></tr></thead><tbody><tr><td>操作失败是否有提示</td><td>提交、保存、删除失败都要提示</td><td>失败时页面没反应</td></tr><tr><td>错误提示是否明确</td><td>告诉用户为什么失败、怎么解决</td><td>只显示&quot;系统错误&quot;</td></tr><tr><td>是否允许重试</td><td>失败后提供重试入口</td><td>失败后只能退出重来</td></tr><tr><td>是否保留用户输入</td><td>提交失败后已填内容不要清空</td><td>失败后表单被清空，用户重新填一遍</td></tr></tbody></table><p><strong>原型与设计稿的交接规范</strong></p><p>原型和最终视觉设计稿是两个东西，但开发接的时候容易混淆。怕浪猫建议做一个清晰的交接规范，让开发一眼知道哪个是原型、哪个是设计稿、哪个是交互说明。</p><p>交接文档必备要素：</p><ol><li>页面清单：列出每个页面名称、对应原型页面链接、对应设计稿链接</li><li>交互说明：每个页面右侧留白写交互说明，用文字描述无法从视觉上直接看出的逻辑</li><li>状态清单：列出该页面所有可能的状态（默认、空、加载、错误、无权限等），分别标注对应设计稿</li><li>动效说明：哪些动画需要开发实现，给出持续时间、缓动函数、触发条件</li><li>变量和全局状态说明：哪些数据是全局的，在不同页面之间如何传递</li></ol><p>建议用Axure的页面注释功能，直接在页面树右侧写交互说明。不要用微信群发语音，语音里的信息开发根本找不到。</p><p><strong>交接检查清单</strong></p><table tabindex="0"><thead><tr><th>检查项</th><th>是否完成</th><th>说明</th></tr></thead><tbody><tr><td>原型已覆盖全部页面</td><td>是/否</td><td>主流程和分支流程都包含</td></tr><tr><td>每个页面已标注交互说明</td><td>是/否</td><td>点击、滑动、跳转、状态变化都写清楚</td></tr><tr><td>设计稿和原型已对齐</td><td>是/否</td><td>颜色、字号、间距一致</td></tr><tr><td>全部状态已画完</td><td>是/否</td><td>默认、空、加载、错误、边界状态</td></tr><tr><td>动效和过渡已说明</td><td>是/否</td><td>持续时间、触发条件、目标状态</td></tr><tr><td>变量和全局状态已说明</td><td>是/否</td><td>登录态、购物车、筛选条件等</td></tr><tr><td>已和开发对评审通过</td><td>是/否</td><td>开发确认没有歧义</td></tr></tbody></table><h3 id="_6-2-5-移动端原型设计要点" tabindex="-1">6.2.5 移动端原型设计要点 <a class="header-anchor" href="#_6-2-5-移动端原型设计要点" aria-label="Permalink to “6.2.5 移动端原型设计要点”">​</a></h3><p>移动端原型的交互和PC端完全是两个逻辑。PC端靠鼠标点击，移动端靠手指触摸。你画移动端原型时如果还只考虑点击，那开发拿到手还得补一堆手势和状态。</p><p><strong>手势交互设计</strong></p><p>移动端有四种常用手势：滑动、长按、拖拽、捏合缩放。每种手势对应不同的场景，不要瞎用。</p><p><strong>常用手势及应用场景</strong></p><table tabindex="0"><thead><tr><th>手势</th><th>典型场景</th><th>交互反馈</th><th>注意事项</th></tr></thead><tbody><tr><td>滑动</td><td>切换Tab、轮播图、列表刷新、删除列表项</td><td>跟随手指移动，松手回弹或切换</td><td>要有明确的滑动边界和惯性效果</td></tr><tr><td>长按</td><td>弹出操作菜单、进入编辑模式、收藏</td><td>按压后震动反馈或背景变暗</td><td>长按时间通常500ms-800ms，太短误触，太长用户等不及</td></tr><tr><td>拖拽</td><td>调整排序、移动图标、拖拽文件</td><td>被拖拽元素半透明，目标位置高亮</td><td>要有明确的放置区域，放下后给出成功反馈</td></tr><tr><td>捏合缩放</td><td>图片查看、地图缩放、网页缩放</td><td>双指距离变化同步缩放</td><td>缩放中心和边界要处理好，不要无限放大</td></tr></tbody></table><p><strong>滑动交互的设计细节</strong></p><p>滑动是最常用的手势，但很多人的原型只画一个&quot;可左右滑动&quot;的箭头，开发看了完全不知道怎么实现。完整的设计应该包含：</p><ul><li>滑动方向：水平还是垂直</li><li>触发区域：整屏可滑还是只有某个区域可滑</li><li>滑动边界：滑到边缘是否回弹，是否显示&quot;没有更多&quot;</li><li>切换效果：是否有过渡动画，动画持续多久</li><li>指示器：当前在第几页，有几个可滑页面</li></ul><p>在Axure中实现滑动：用动态面板包裹可滑动内容，设置&quot;拖动时&quot;交互，用Move动作让内容跟随鼠标移动。松手时根据位置判断切换到上一页/下一页/回弹。</p><p><strong>长按交互的设计细节</strong></p><p>长按操作隐蔽，用户不一定知道。需要给视觉暗示：比如列表项右侧有三个点图标，或者文字提示&quot;长按更多操作&quot;。</p><p>在Axure中实现长按：给元件添加OnMouseDown事件，设置Wait 700ms，然后触发动作。如果OnMouseOut在700ms内发生，则取消动作。可以用条件判断实现这个逻辑。</p><p><strong>拖拽交互的设计细节</strong></p><p>拖拽适合排序、整理等场景。设计时要明确：</p><ul><li>可拖拽元素：哪些元素可以拖，哪些不能拖</li><li>拖拽时的视觉变化：透明度变化、阴影、缩放</li><li>放置目标：哪些地方可以放置，放不进去怎么办</li><li>排序规则：拖放到两个元素之间时，插入到谁前面</li></ul><p>在Axure中实现拖拽：用Move动作配合&quot;拖动时&quot;事件，让元件跟随鼠标位置。松手时判断位置是否在某个目标区域内，是则移动到新位置，否则回到原位。</p><p><strong>捏合缩放的设计细节</strong></p><p>捏合缩放主要在图片浏览、地图、PDF阅读场景。Axure本身对双指手势的支持有限，但原型中可以通过文字说明+手势标注来表达。</p><p>标注内容：</p><ul><li>最小缩放比例和最大缩放比例</li><li>缩放中心：以手指中心为缩放中心还是屏幕中心</li><li>缩放后的操作：双击还原、双指缩放、单击隐藏UI</li></ul><p><strong>移动端特殊状态</strong></p><p>移动端比PC端多了一堆特殊状态，这些状态如果没考虑到，用户在外面用起来会很崩溃。</p><p><strong>弱网状态</strong></p><p>用户在地铁、电梯、地下停车场里会频繁遇到弱网。弱网状态设计要点：</p><ul><li>不要长时间白屏：1秒内还没数据就显示骨架屏或加载提示</li><li>请求超时：超过3-5秒没有响应要给出&quot;网络较慢&quot;提示</li><li>降级方案：图片加载失败时显示占位图，视频加载失败时提示&quot;重试&quot;</li><li>重试机制：提供&quot;点击重试&quot;按钮，不要让用户只能退出App</li></ul><p>弱网状态文案建议：</p><table tabindex="0"><thead><tr><th>状态</th><th>文案建议</th><th>反面教材</th></tr></thead><tbody><tr><td>加载慢</td><td>网络好像有点慢，正在努力加载中</td><td>加载中...</td></tr><tr><td>请求超时</td><td>网络连接超时，请检查后重试</td><td>请求失败</td></tr><tr><td>图片加载失败</td><td>图片加载失败，点击重新加载</td><td>空白图片</td></tr><tr><td>数据加载失败</td><td>内容加载失败，下拉刷新试试</td><td>暂无数据</td></tr></tbody></table><p><strong>离线状态</strong></p><p>离线比弱网更严重。用户可能完全没网。离线状态设计要点：</p><ul><li>区分&quot;从未加载过&quot;和&quot;加载过但现在没网&quot;：前者显示引导页，后者显示已缓存内容+离线提示</li><li>可离线功能：阅读、笔记、播放已下载内容等，要明确告诉用户哪些可以离线用</li><li>自动重连：网络恢复后自动刷新，不需要用户手动操作</li><li>离线操作队列：用户在离线时提交的操作，恢复网络后自动同步</li></ul><p>在Axure中设计离线状态：可以做一个&quot;网络状态&quot;全局变量，值为online/offline。页面OnLoad时根据变量值显示不同状态。切网时通过条件逻辑切换变量和页面状态。</p><p><strong>推送通知</strong></p><p>推送通知是移动端特有的触达方式。原型里经常只画一个&quot;推送&quot;开关，但完整的推送设计应该包含：</p><ul><li>通知触发条件：什么情况下发推送，发几次，间隔多久</li><li>通知内容结构：标题、正文、缩略图、动作按钮</li><li>点击通知后的跳转：打开App到哪个页面，是否带参数</li><li>通知设置：用户可以在设置里关闭哪些类型的通知</li><li>勿扰模式：夜间、会议期间是否要合并或延迟发送</li></ul><p>推送通知设计原则：</p><ul><li>不要滥用：一天内同一类推送不要超过3条，多了用户直接关通知</li><li>内容具体：不要&quot;您有一条新消息&quot;，要&quot;张三回复了你的评论：写得不错&quot;</li><li>提供直达：点击推送后直接进入相关内容，不要让用户再去找</li><li>允许撤销：用户误触后5秒内可以撤销，收回通知</li></ul><p>在Axure中模拟推送：可以用动态面板做一个&quot;通知横幅&quot;，默认隐藏。通过按钮触发Show，设置自动Hide（Wait 3秒后隐藏）。</p><p><strong>移动端原型尺寸建议</strong></p><p>画移动端原型时，画布尺寸要按目标设备来，不要在PC尺寸上画移动端。</p><table tabindex="0"><thead><tr><th>设备类型</th><th>建议画布尺寸</th><th>说明</th></tr></thead><tbody><tr><td>iPhone 14/15</td><td>393 × 852</td><td>带灵动岛状态栏要留出空间</td></tr><tr><td>iPhone SE</td><td>375 × 667</td><td>小屏设备，注意底部安全区</td></tr><tr><td>Android主流</td><td>360 × 800</td><td>全面屏，底部手势区域要避开</td></tr><tr><td>iPad</td><td>768 × 1024</td><td>横屏竖屏两种状态都要考虑</td></tr></tbody></table><p>底部安全区：全面屏手机底部有手势条区域，重要按钮不要贴底，至少留34-44px。顶部状态栏：时间、信号、电量区域不要放重要信息。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to “本章小结”">​</a></h2><p>Axure是产品经理画原型的标配工具。掌握元件使用、动态面板、交互动作，就能画出中保真原型。加上高保真的视觉还原和完整的状态设计，就能画出给开发参考的高保真原型。移动端原型还要额外考虑手势交互和弱网、离线、推送等特殊状态。</p><table tabindex="0"><thead><tr><th>本章核心知识点</th><th>一句话总结</th></tr></thead><tbody><tr><td>元件使用</td><td>矩形+文本=90%的原型内容</td></tr><tr><td>动态面板</td><td>带状态的元件，实现Tab切换等交互</td></tr><tr><td>中继器</td><td>批量生成重复内容，如列表页</td></tr><tr><td>交互事件</td><td>OnClick、OnMouseEnter等触发条件</td></tr><tr><td>交互动作</td><td>Show/Hide/Set Text等响应行为</td></tr><tr><td>条件逻辑</td><td>if-else让交互有分支判断</td></tr><tr><td>变量使用</td><td>全局变量跨页面，局部变量做临时计算</td></tr><tr><td>四状态设计</td><td>默认/悬停/按下/禁用，缺一不可</td></tr><tr><td>表单验证</td><td>实时验证+提交验证，错误文案要具体</td></tr><tr><td>加载状态</td><td>骨架屏/Loading/进度条，按场景选择</td></tr><tr><td>高保真要点</td><td>视觉还原+完整交互+页面跳转</td></tr><tr><td>原型评审</td><td>功能完整、交互一致、边界、空状态、错误处理</td></tr><tr><td>交接规范</td><td>页面清单、交互说明、状态清单、动效说明、变量说明</td></tr><tr><td>移动端要点</td><td>手势交互+弱网/离线/推送状态+安全区</td></tr></tbody></table><p>觉得有用？收藏起来，下次画原型直接照抄。</p><p>你画原型时踩过什么坑？评论区说说。</p><p>关注怕浪猫，下期我们讲&quot;产品需求文档（PRD）撰写&quot;——PRD怎么写才不会被开发怼，需求怎么描述才没有歧义，怕浪猫的经验之谈。</p><p>系列进度 6/16</p><p><strong>下章预告：</strong> 第7章，PRD是产品经理最重要的输出物之一。很多人写的PRD——逻辑混乱、细节缺失、异常流程全靠开发脑补。下一章，我教你写出一份&quot;开发看了不骂人&quot;的PRD。</p>',194)])])}const q=d(a,[["render",e]]);export{b as __pageData,q as default};
